using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes the provided message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Returns the server's current UTC time.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("O");
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the application's current configuration data.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { EnableCaching = true, EnableMetrics = false }
        };
        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists the available API endpoints and their descriptions.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Description = "Health check" }
        };
        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

